def main():
    data = load_data()
    updated = 0
    for q in data:
        qid = q["id"]
        # Standardize true answers found in PDFs by AI review
        if qid == 102: q["answer"] = "C" # PDF has B, correct is C
        if qid == 105: q["answer"] = "B" # PDF has D, correct is B
        if qid == 106: q["answer"] = "B" # PDF has C, correct is B
        if qid == 110: q["answer"] = "D" # PDF has B, correct is D
        if qid == 111: q["answer"] = "C" # PDF has D, correct is C
        if qid == 115: q["answer"] = "D" # Correct as D but explanation updated
        if qid == 117: q["answer"] = "A" # PDF has C, correct is A

        if qid in manual_explanations:
            q["explanation_vi"] = manual_explanations[qid]
            updated += 1
            
    save_data(data)
    print(f"Injected custom explanations for Q101 - Q130! ({updated} questions updated)")

if __name__ == "__main__":
    main()
